#!/usr/bin/env bash
set -euo pipefail

# ============================================================
# AIFX010 - Hoax Hertz | Batch evaluation for SVM & LogReg
# Requires: eval_batch.py and .joblib models already trained.
# ============================================================

# --- main configs (adjust if necessary) ---
TRAIN_CSV="ml/factory/pipeline/task_0_data/data_processed/train_clips.csv"
DEV_CSV="ml/factory/pipeline/task_0_data/data_processed/dev_clips.csv"
SUFFIX=".feat.npz"

# Models (use names generated by your run.sh)
EXP_DIR="ml/factory/experiments/run_auto"
SVM_MODEL="${EXP_DIR}/clipclf_svm_optuna.joblib"
LR_MODEL="${EXP_DIR}/clipclf_logreg_optuna.joblib"

# Outputs
OUT_DIR="${EXP_DIR}/eval"
mkdir -p "${OUT_DIR}"

# --- helper ---
eval_one () {
  local TAG="$1"       # ex: svm_dev
  local CSV="$2"       # caminho do csv
  local MODEL="$3"     # caminho do .joblib

  echo "======================================================================"
  echo "[EVAL] ${TAG}"
  echo "  CSV:   ${CSV}"
  echo "  MODEL: ${MODEL}"
  echo "----------------------------------------------------------------------"

  python ml/factory/pipeline/task_4_eval/eval_batch.py \
    --csv "${CSV}" \
    --model "${MODEL}" \
    --suffix "${SUFFIX}" \
    --out-json "${OUT_DIR}/${TAG}_metrics.json" \
    --out-preds "${OUT_DIR}/${TAG}_preds.csv" \
    --dump-topk 50

  echo "[OK] Wrote:"
  echo "  - ${OUT_DIR}/${TAG}_metrics.json"
  echo "  - ${OUT_DIR}/${TAG}_preds.csv"
}

# --- quick checks ---
for f in "${SVM_MODEL}" "${LR_MODEL}" "${TRAIN_CSV}" "${DEV_CSV}"; do
  if [[ ! -f "${f}" ]]; then
    echo "[ERROR] File not found: ${f}" >&2
    exit 1
  fi
done

# --- runs ---
eval_one "svm_train" "${TRAIN_CSV}" "${SVM_MODEL}"
eval_one "svm_dev"   "${DEV_CSV}"   "${SVM_MODEL}"

eval_one "logreg_train" "${TRAIN_CSV}" "${LR_MODEL}"
eval_one "logreg_dev"   "${DEV_CSV}"   "${LR_MODEL}"

# --- comparative summary ---
python - <<'EOF'
import json, pathlib
out = pathlib.Path("ml/factory/experiments/run_auto/eval")
pairs = {
  "svm_train": out/"svm_train_metrics.json",
  "svm_dev":   out/"svm_dev_metrics.json",
  "logreg_train": out/"logreg_train_metrics.json",
  "logreg_dev":   out/"logreg_dev_metrics.json",
}
def load(p):
  try:
    with open(p, "r", encoding="utf-8") as f: return json.load(f)
  except Exception: return {}
summ = {k: load(v) for k,v in pairs.items()}

def safe(x, *ks, default=None):
  for k in ks:
    if isinstance(x, dict) and k in x: x = x[k]
    else: return default
  return x

def line(tag):
  acc = safe(summ[tag], "accuracy", default=None)
  auc = safe(summ[tag], "roc_auc_pos_class", "roc_auc", default=None)
  n   = safe(summ[tag], "n_used", default=None)
  return {"split": tag, "accuracy": acc, "roc_auc": auc, "n_used": n}

table = [line(k) for k in ["svm_train","svm_dev","logreg_train","logreg_dev"]]

best = max(
  (("svm_dev", safe(summ["svm_dev"], "accuracy", default=0.0)),
   ("logreg_dev", safe(summ["logreg_dev"], "accuracy", default=0.0))),
  key=lambda t: (t[1] if t[1] is not None else -1)
)

summary = {
  "table": table,
  "best_on_dev": {"model": best[0].split("_")[0], "accuracy": best[1]}
}
with open(out/"summary_eval.json", "w", encoding="utf-8") as f:
  json.dump(summary, f, ensure_ascii=False, indent=2)
print(json.dumps(summary, indent=2))
EOF

echo "======================================================================"
echo "[DONE] Evaluation completed. Outputs in: ${OUT_DIR}"
echo "  - *_metrics.json, *_preds.csv and summary_eval.json"
echo "======================================================================"
